import type { AuditEntry } from '../types.js';

export function profileRefreshAudit(profileId: string): AuditEntry {
  return {
    id: `profile-refresh-${profileId}`,
    timestamp: new Date().toISOString(),
    operation: 'profile_refresh',
    functionId: 'mem::profile-refresh',
    targetIds: [profileId],
    details: { refreshed: true },
  };
}
